content = "import urllib.request\nimport json\nimport csv\nimport os\nimport time\nimport smtplib\nfrom email.mime.text import MIMEText\nfrom datetime import date, datetime\nfrom secrets_loader import get_secret\nfrom alerts import send_alert\nfrom etf_confidence_scan import is_cash_market_hours, QUALIFYING_PATH\n\nLOG_PATH = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'etf_iv_percentile_log.csv')\nIV_THRESHOLD = 80.0\nPOLL_INTERVAL_SECONDS = 300\nalerted_today = set()\ncurrent_day = date.today().isoformat()\n\ndef get_qualifying_symbols():\n    if not os.path.exists(QUALIFYING_PATH):\n        return []\n    with open(QUALIFYING_PATH, 'r') as f:\n        reader = csv.DictReader(f)\n        return [row['symbol'] for row in reader]\n\ndef fetch_iv_data(symbols):\n    if not symbols:\n        return {}\n    token = get_secret('orats-api-token')\n    results = {}\n    for i in range(0, len(symbols), 10):\n        batch = symbols[i:i+10]\n        ticker_str = ','.join(batch)\n        url = f'https://api.orats.io/datav2/cores?token={token}&ticker={ticker_str}&fields=ticker,ivPctile1y,ivRank1y'\n        with urllib.request.urlopen(url) as response:\n            data = json.loads(response.read())\n            for item in data['data']:\n                results[item['ticker']] = (item.get('ivPctile1y'), item.get('ivRank1y'))\n    return results\n"
with open('etf_iv_percentile_alert.py', 'w') as f:
    f.write(content)
